Prolog:
sTextKey = Trim(pTextKey);
sLocale = Trim(pLocale);
sOutputFile = Trim(pOutputFile);
sResolvedText = '';
sStatus = 'MISSING';
sComment = '';
sMissingMarker = '[missing:' | sTextKey | ']';
If(sLocale @= ''); sLocale = 'en-US'; EndIf;
If(sTextKey @= '');
  sStatus = 'ERROR';
  sComment = 'Text key is required.';
  sResolvedText = '[missing:]';
ElseIf(CubeExists('IMF.C.Text') = 0);
  sStatus = 'ERROR';
  sComment = 'IMF.C.Text is not deployed.';
  sResolvedText = sMissingMarker;
ElseIf(DimensionElementExists('IMF.D.TextKey', sTextKey) = 0);
  sStatus = 'ERROR';
  sComment = 'Text key is not deployed in IMF.D.TextKey.';
  sResolvedText = sMissingMarker;
Else;
  sResolvedText = CellGetS('IMF.C.Text', sTextKey, sLocale, 'Text');
  If(Trim(sResolvedText) @<> '');
    sStatus = 'FOUND';
    sComment = 'Translation found for requested locale.';
  Else;
    sResolvedText = sMissingMarker;
    sStatus = 'MISSING';
    sComment = 'No translation exists for the requested locale.';
  EndIf;
EndIf;
If(sOutputFile @<> '');
  ASCIIOutput(sOutputFile, 'TextKey', 'RequestedLocale', 'ResolvedLocale', 'Status', 'ResolvedText', 'Comment');
  ASCIIOutput(sOutputFile, sTextKey, sLocale, sLocale, sStatus, sResolvedText, sComment);
Else;
  LogOutput('INFO', 'IMF.P.Text.Resolve|' | sTextKey | '|' | sLocale | '|' | sStatus | '|' | sResolvedText);
EndIf;
